bool transcriptHasDisplayText(String? value) => value?.isNotEmpty == true;

String? transcriptTrimmedTextOrNull(String? value) {
  final trimmed = value?.trim();
  if (trimmed == null || trimmed.isEmpty) return null;
  return trimmed;
}

bool transcriptHasNonBlankText(String? value) {
  return transcriptTrimmedTextOrNull(value) != null;
}

String transcriptJoinNonEmptyLines(Iterable<String?> parts) {
  return parts.whereType<String>().where(transcriptHasDisplayText).join('\n');
}

String transcriptJoinInfoParts(Iterable<String> parts) {
  return parts.join(' • ');
}

String? transcriptJoinOptionalInfoParts(Iterable<String> parts) {
  final partList = parts.toList(growable: false);
  return partList.isEmpty ? null : transcriptJoinInfoParts(partList);
}

import '../../../../../core/protocol/navivox_event.dart';
import 'transcript_display_text.dart';

String transcriptPlainTextForMessage(NavivoxChatMessage message) {
  return switch (message.kind) {
    NavivoxMessageKind.text => message.text ?? '',
    NavivoxMessageKind.voice => message.voice?.transcript ?? '',
    NavivoxMessageKind.toolCall => transcriptJoinNonEmptyLines([
      message.toolCall?.name,
      message.toolCall?.status,
      message.toolCall?.summary,
    ]),
    NavivoxMessageKind.safetyWarning ||
    NavivoxMessageKind.approvalRequest => transcriptJoinNonEmptyLines([
      message.safetyNotice?.message,
      message.safetyNotice?.risk,
    ]),
  };
}

